// browser-extension/public/wasm/video_editor_wasm.js
// Mock WebAssembly module function.
// This matches the exact Embind and MEMFS (FS) interfaces generated by Emscripten,
// allowing the React frontend extension to run and render dynamically in the browser
// immediately without requiring the local installation of the Emscripten SDK toolchain.

const globalVirtualFS = {};

class MockVideoTimelineManager {
  constructor(profileName) {
    this.profileName = profileName;
    this.clips = [];
    console.log(`[Wasm Engine Mock] Initialized with profile: ${profileName}`);
  }

  initializeProfile(profileName) {
    this.profileName = profileName;
    console.log(`[Wasm Engine Mock] Re-initialized profile: ${profileName}`);
    return true;
  }

  addClip(type, source, trackIndex) {
    this.clips.push({ type, source, trackIndex });
    console.log(`[Wasm Engine Mock] Clip added: ${source} (Type: ${type}, Track: ${trackIndex})`);
    return true;
  }

  printTimelineInfo() {
    console.log(`[Wasm Engine Mock] Timeline: ${this.clips.length} active clips.`);
  }

  detectAndApplyAutoCut(trackIndex, modelPath) {
    console.log(`[Wasm Engine Mock] Running scene detection on track ${trackIndex}...`);
    
    // Generate mock cut points based on the active clip name seed
    const seed = this.clips.length > 0 ? this.clips[0].source.length : 12;
    const cut1 = 60 + (seed % 20);
    const cut2 = 150 + ((seed * 7) % 30);
    const cut3 = 240 - ((seed * 3) % 20);
    
    // Mimic Embind std::vector<int> wrapper structure
    return {
      size: () => 3,
      get: (idx) => {
        if (idx === 0) return cut1;
        if (idx === 1) return cut2;
        if (idx === 2) return cut3;
        return 0;
      }
    };
  }

  exportFrameToPpm(frameIndex, outputPath, width, height) {
    console.log(`[Wasm Engine Mock] Exporting frame ${frameIndex} to Virtual MEMFS: ${outputPath} (${width}x${height})`);
    
    // Generate valid binary PPM P6 format bytes (gradient pattern)
    const header = `P6\n${width} ${height}\n255\n`;
    const headerBytes = new TextEncoder().encode(header);
    const pixelBytes = new Uint8Array(width * height * 3);
    
    // Draw procedural color gradient
    for (let y = 0; y < height; ++y) {
      for (let x = 0; x < width; ++x) {
        const idx = (y * width + x) * 3;
        pixelBytes[idx] = Math.floor((x * 255) / width);     // Red channel gradient
        pixelBytes[idx + 1] = Math.floor((y * 255) / height); // Green channel gradient
        pixelBytes[idx + 2] = 160;                           // Blue constant channel
      }
    }
    
    // Concatenate header and binary payload
    const ppmBytes = new Uint8Array(headerBytes.length + pixelBytes.length);
    ppmBytes.set(headerBytes);
    ppmBytes.set(pixelBytes, headerBytes.length);
    
    // Store inside the mock file system
    globalVirtualFS[outputPath] = ppmBytes;
    return true;
  }
}

const createVideoEditorModule = async (options = {}) => {
  // Simulate load latency
  await new Promise((resolve) => setTimeout(resolve, 300));
  
  return {
    VideoTimelineManager: MockVideoTimelineManager,
    FS: {
      readFile: (path) => {
        if (globalVirtualFS[path]) {
          return globalVirtualFS[path];
        }
        throw new Error(`File not found in Virtual MEMFS: ${path}`);
      },
      unlink: (path) => {
        delete globalVirtualFS[path];
      }
    }
  };
};

export default createVideoEditorModule;
